query:
-- Fix categories based on item names
UPDATE menuItems SET category = 'Mains' WHERE name IN ('Pad Thai', 'Butter Chicken', 'Beef Rendang', 'Pho Bo') AND category = 'Other';
UPDATE menuItems SET category = 'Snacks' WHERE name IN ('Chicken Momo', 'Samosa (2 pcs)', 'Spring Rolls (3 pcs)') AND category = 'Other';
UPDATE menuItems SET category = 'Drinks' WHERE name IN ('Mango Lassi', 'Thai Iced Tea', 'Coconut Water') AND category = 'Other';

-- Remove duplicate modifier lists (keep the first set with IDs 1-3, remove 4-6)
DELETE FROM menuItemModifierLists WHERE modifierListId IN (4, 5, 6);
DELETE FROM modifiers WHERE modifierListId IN (4, 5, 6);
DELETE FROM modifierLists WHERE id IN (4, 5, 6);

